							{console.log(isUpload)}
							{ Object.values(isUpload).filter( value => value ? <CancelIcon /> : null)}
							<PhotoWrapper ref={node => {
								const map = getMap(photoWrapperRef)
								if (node) {
									map.set(photo, node)
								}
							}}>
								<PhotoInput ref={node => {
								const map = getMap(photoInputRef)
								if (node) {
									map.set(photo, node)
								}
							}} onChange={() => handleImageUpload(photo)} type='file' accept='image/png, image/jpg'></PhotoInput></PhotoWrapper>
